const items = $('Factura').first().json.results[0].items || [];

let subtotal = 0;

for (const item of items) {
  const price = Number(item.price || 0);
  const quantity = Number(item.quantity || 0);
  subtotal += price * quantity;
}

return [{
  json: {
    ...$json,
    subtotal_calculado: subtotal
  }
}];

const valorCompra = $input.first().json.subtotal_calculado;
const puntosGanados = Math.ceil(valorCompra / 1000);

return [{
  json: {
    ...$json,
    puntosGanados
  }
}];

// Cascada de detección de contacto: cédula → teléfono → email.
// Devuelve { total, contacts:[uno], matchedBy } igual que /contacts/search.
const j = $json;
const TOKEN = '__GHL_TOKEN__';
const LOC = 'jzrg6bPH71ccLohGddsN';
const CED_FIELD = '4C6TxwNRElYAB1HFkJb4';
const H = { Authorization: 'Bearer ' + TOKEN, Version: '2021-07-28', 'Content-Type': 'application/json' };
const norm = t => String(t || '').replace(/[^0-9]/g, '').replace(/^57(?=\d{10}$)/, '');
const search = (body) => this.helpers.httpRequest({ method:'POST', url:'https://services.leadconnectorhq.com/contacts/search', headers:H, body, json:true });

const ident = String(j.identification || '').trim();
const tel   = norm((j.phones || [])[0] && (j.phones || [])[0].number);
const email = String(((j.contacts || [])[0] || {}).email || '').trim().toLowerCase();

let found = null, matchedBy = '';
// 1) por cédula (campo personalizado)
if (ident) {
  const r = await search({ locationId:LOC, pageLimit:10, page:1, filters:[{ field:'customFields.'+CED_FIELD, operator:'eq', value:ident }] });
  found = (r.contacts || [])[0] || null; if (found) matchedBy = 'identificacion';
}
// 2) por teléfono (contains + verificación exacta)
if (!found && tel && tel.length >= 7) {
  const r = await search({ locationId:LOC, pageLimit:10, page:1, filters:[{ field:'phone', operator:'contains', value:tel }] });
  found = (r.contacts || []).find(c => norm(c.phone) === tel) || null; if (found) matchedBy = 'telefono';
}
// 3) por email (eq + verificación exacta)
if (!found && email) {
  const r = await search({ locationId:LOC, pageLimit:10, page:1, filters:[{ field:'email', operator:'eq', value:email }] });
  found = (r.contacts || []).find(c => String(c.email||'').trim().toLowerCase() === email) || null; if (found) matchedBy = 'email';
}
return { json: { total: found ? 1 : 0, contacts: found ? [found] : [], matchedBy } };

