const contact = $('Buscar contacto').first().json.contacts[0];
const cf = contact.customFields || [];

// Leer por ID de campo (NO por posicion) con coercion numerica segura
const num = (id) => { const f = cf.find(x => x.id === id); const v = f ? Number(f.value) : 0; return isNaN(v) ? 0 : v; };

const PUNTOS_ID    = 'UfFc9GjS1K9az8nactO5'; // saldo de puntos
const HIST_ID      = 'ciYvzjlWfz9RcmIlqRkO'; // puntos historicos (total otorgado)
const HISTORIAL_ID = 'wdfNkPf305JjwPdTUBwS'; // fechas de recompra

const puntosActuales = num(PUNTOS_ID);
const puntosNuevos   = Number($('Code in JavaScript1').first().json.puntosGanados) || 0;
const totalPuntos    = puntosActuales + puntosNuevos;
const puntosHistory  = num(HIST_ID) + puntosNuevos;

const histField        = cf.find(f => f.id === HISTORIAL_ID);
const currentHistorial = histField?.value || '';
const today            = new Date().toISOString().split('T')[0];
const newHistorial     = currentHistorial ? currentHistorial + ',' + today : today;
const fechaUltimaRecompra = today;

// ── Enriquecer: rellenar en GHL solo lo que FALTE, con el dato de Siigo ──
// Nunca pisa un valor que GHL ya tenga: si existe, se reenvia el mismo.
const cli = (() => { try { return $('Cliente').first().json || {}; } catch (e) { return {}; } })();
const norm = t => String(t || '').replace(/[^0-9]/g, '').replace(/^57(?=\d{10}$)/, '');

const telSiigo   = norm((cli.phones || [])[0]?.number);
const mailSiigo  = ((cli.contacts || [])[0]?.email || '').trim();
const nomSiigo   = [ (cli.contacts || [])[0]?.first_name, (cli.contacts || [])[0]?.last_name ].filter(Boolean).join(' ').trim();

const telGHL  = norm(contact.phone);
const mailGHL = String(contact.email || '').trim();
const nomGHL  = String(contact.name || '').trim();

// valor final = el de GHL si lo tiene; si no, el de Siigo (puede quedar vacio)
const phone = telGHL  || telSiigo  || '';
const email = mailGHL || mailSiigo || '';
const name  = nomGHL  || nomSiigo  || '';
const completo = { phone: !!telGHL, email: !!mailGHL, name: !!nomGHL };

return [{
  json: { contactId: contact.id, puntosActuales, puntosNuevos, totalPuntos, puntosHistory, newHistorial, fechaUltimaRecompra,
          phone, email, name, __yaTenia: completo }
}];

const items = $input.all();

const fileItem  = items[0]?.json;
const siigoItem = items[1]?.json;

let processedData = [];
try {
    if (Array.isArray(fileItem)) {
        if (fileItem.length > 0 && fileItem[0].data_to_save && Array.isArray(fileItem[0].data_to_save)) {
            processedData = fileItem[0].data_to_save;
        } else {
            processedData = fileItem;
        }
    } else if (fileItem && fileItem.data_to_save && Array.isArray(fileItem.data_to_save)) {
        processedData = fileItem.data_to_save;
    } else if (fileItem && fileItem.data && Array.isArray(fileItem.data)) {
        processedData = fileItem.data;
    }
} catch (e) {
    processedData = [];
}

const allInvoices     = siigoItem?.results || [];
const processedNames  = new Set(processedData.map(p => p.name));
const newInvoices     = allInvoices.filter(inv => !processedNames.has(inv.name));

const updatedProcessed = [
    ...processedData,
    ...newInvoices.map(inv => ({ name: inv.name, id: inv.id, date: inv.date }))
];

const trimmedProcessed = updatedProcessed.slice(-2000);

return [{
    json: {
        new_invoices:       newInvoices,
        new_count:          newInvoices.length,
        all_invoices_count: allInvoices.length,
        processed_count:    processedData.length,
        data_to_save:       JSON.stringify(trimmedProcessed, null, 2)
    }
}];

const BLOCKED_IDS=new Set(['7777777777777','222222222222']);

// El log se alimenta de las DOS ramas: contacto existente (Buscar contacto) y
// contacto RECIEN CREADO (HTTP Request). Antes solo la primera estaba conectada,
// por eso las compras de clientes nuevos nunca quedaban registradas en puntos_log.
let bc = {};
try { bc = $('Buscar contacto').first().json.contacts[0] || {}; } catch (e) { bc = {}; }
if (!bc || !bc.id) {
  try {
    const r = $('HTTP Request').first().json || {};
    const c = r.contact || r;
    if (c && c.id) bc = { id:c.id, firstName:c.firstName||'', lastName:c.lastName||'', phone:c.phone||'' };
  } catch (e) { /* venimos de la rama de contacto existente */ }
}

const invoice = $('Code in JavaScript1').first().json;

// Factura del ciclo actual (antes: results[0] = siempre la primera del lote)
let fv='', fdate='';
try { const f=$('Loop Over Items').item.json; fv=f.name||''; fdate=String(f.date||'').slice(0,10); } catch(e){}
if(!fv){ try{ const f=$('Factura').first().json.results[0]; fv=f.name||''; fdate=String(f.date||'').slice(0,10); }catch(e){} }

const puntos  = Number(invoice.puntosGanados)||0;
const siigoId = String(invoice.identification||'').trim();
if(BLOCKED_IDS.has(siigoId)) return [];

// Nombre/telefono: si el contacto recien creado no los trae, se usan los de Siigo
let nombre = ((bc.firstName||'')+' '+(bc.lastName||'')).trim();
let tel = bc.phone||'';
try {
  const cli = $('Cliente').first().json || {};
  if(!nombre){ const n=cli.name; nombre = Array.isArray(n)? n.join(' ') : String(n||''); }
  if(!tel){ tel = ((cli.phones||[])[0]||{}).number || ''; }
} catch(e){}

const now=new Date();
return [{ json: {
  ext_id: Date.now().toString(36)+Math.random().toString(36).slice(2),
  timestamp: (fdate? fdate+'T12:00:00Z' : now.toISOString()),
  fecha: (fdate||now.toISOString().split('T')[0]),
  tipo:'suma_puntos',
  contact_id: bc.id||'',
  contact_name: nombre,
  phone: tel,
  points: puntos,
  source:'siigo',
  invoice_id: fv||null,
  siigo_id: siigoId||null
} }];

// Factura ACTUAL del loop (antes se usaba results[0] = siempre la primera del lote)
let inv = {};
